import requests


class SAMLServiceProvider:
    def __init__(self, sp_entity_id, acs_url):
        self.sp_entity_id = sp_entity_id
        self.acs_url = acs_url
    
    def generate_request_id(self):
        return f"_{uuid.uuid4()}"
    
    def get_timestamp(self):
        return datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    
    def build_authn_request(self, destination_url, user_info=None):
        request_id = self.generate_request_id()
        issue_instant = self.get_timestamp()
        
        saml_request = f'''<samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{destination_url}"
    AssertionConsumerServiceURL="{self.acs_url}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{self.sp_entity_id}</saml:Issuer>'''
        
        if user_info:
            saml_request += f'''
    <saml:Subject>
        <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress">{user_info.get('email', '')}</saml:NameID>
    </saml:Subject>'''
            
            if 'attributes' in user_info:
                saml_request += '''
    <saml:AttributeStatement>'''
                for attr_name, attr_value in user_info['attributes'].items():
                    saml_request += f'''
        <saml:Attribute Name="{attr_name}">
            <saml:AttributeValue>{attr_value}</saml:AttributeValue>
        </saml:Attribute>'''
                saml_request += '''
    </saml:AttributeStatement>'''
        
        saml_request += '''
    <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress" AllowCreate="true"/>
    <samlp:RequestedAuthnContext Comparison="exact">
        <saml:AuthnContextClassRef>urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport</saml:AuthnContextClassRef>
    </samlp:RequestedAuthnContext>
</samlp:AuthnRequest>'''
        
        return saml_request
    
    def encode_saml_request(self, saml_request):
        compressed = zlib.compress(saml_request.encode('utf-8'))[2:-4]
        encoded = base64.b64encode(compressed).decode('utf-8')
        return encoded
    
    def encode_saml_request_base64_only(self, saml_request):
        encoded = base64.b64encode(saml_request.encode('utf-8')).decode('utf-8')
        return encoded
    
    def send_authn_request(self, destination_url, user_info=None, relay_state=None, use_compression=True):
        saml_request = self.build_authn_request(destination_url, user_info)
        
        if use_compression:
            encoded_request = self.encode_saml_request(saml_request)
        else:
            encoded_request = self.encode_saml_request_base64_only(saml_request)
        
        post_data = {
            'SAMLRequest': encoded_request
        }
        
        if relay_state:
            post_data['RelayState'] = relay_state
        
        response = requests.post(destination_url, data=post_data)
        return response
    
    def get_redirect_url(self, destination_url, user_info=None, relay_state=None):
        saml_request = self.build_authn_request(destination_url, user_info)
        encoded_request = self.encode_saml_request(saml_request)
        
        params = {
            'SAMLRequest': encoded_request
        }
        
        if relay_state:
            params['RelayState'] = relay_state
        
        redirect_url = f"{destination_url}?{urlencode(params)}"
        return redirect_url


